declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';exigirPermiso('system_errors.manage');$id=cmsId($_GET['id']??0);$q=obtenerConexion()->prepare('SELECT e.*,CONCAT_WS(" ",u.nombre,u.apellido) usuario,u.rol,CONCAT_WS(" ",a.nombre,a.apellido) revisado_por FROM errores_sistema e LEFT JOIN usuarios u ON u.id=e.usuario_id LEFT JOIN usuarios a ON a.id=e.actualizado_por WHERE e.id=:id');$q->execute(['id'=>$id]);$error=$q->fetch();if(!$error){cmsFlash('error','Error no encontrado.');header('Location:index.php');exit;}$contexto=json_decode((string)$error['contexto_sanitizado'],true)?:[];cmsCabecera('Error operativo #'.$id,'errores/index.php','El usuario final solamente recibe el identificador de seguimiento.');
