estado?'selected':''?>><?=atenea_e($estado==='revisando'?'Revisado':ucfirst($estado))?></option><?php endforeach;?></select><label class="form-label" for="observacionError">Observación segura</label><textarea class="form-control mb-3" id="observacionError" name="observacion" maxlength="1000" rows="5"><?=atenea_e((string)$error['observacion_resolucion'])?></textarea><button class="btn btn-primary w-100" data-atenea-confirm="state">Guardar revisión</button></form><?php if($error['usuario_id']):?><a class="btn btn-outline-secondary w-100 mt-2" href="<?=atenea_url('src/dashboard/usuarios/detalle.php?id='.(int)$error['usuario_id'].'#errores')?>">Abrir cuenta</a><?php endif;?></div></div></div></div><?php cmsPie();
